def update_account_balances(transactions):
    """
    Updates account balances based on a list of financial transactions.

    Args:
        transactions: A list of dictionaries representing financial transactions.
    """

    # Initialize account balances
    account_balances = {}

    # Iterate through transactions
    for transaction in transactions:
        # Get transaction details
        account = transaction['account']
        amount = transaction['amount']

        # Update account balance
        if account in account_balances:
            account_balances[account] += amount
        else:
            account_balances[account] = amount

    # Return updated account balances
    return account_balances